export function getLangFromUrl(url: URL) {
  const [, lang] = url.pathname.split('/');
  if (lang in languages) return lang as keyof typeof languages;
  return defaultLang;
}

export function useTranslations(lang: keyof typeof languages) {
  return function t(key: keyof typeof translations[typeof defaultLang]) {
    return translations[lang][key] || translations[defaultLang][key];
  }
}

export function getTranslation(lang: keyof typeof languages, key: string): string {
  const langDict = translations[lang] as Record<string, string>
  const defaultDict = translations[defaultLang] as Record<string, string>
  return langDict[key] || defaultDict[key] || key
}